final class HuntRewardClaimService{private $inventory;private $capacity;private $rewards;private $wallet;private $progression;private $instances;private $classification;public function __construct(InventoryService $inventory,PendingRewardCapacityService $capacity,HuntRewardService $rewards,WalletService $wallet,CharacterProgressionService $progression,ItemInstanceService $instances,ItemClassification $classification){$this->inventory=$inventory;$this->capacity=$capacity;$this->rewards=$rewards;$this->wallet=$wallet;$this->progression=$progression;$this->instances=$instances;$this->classification=$classification;}public function claimAllPendingForCharacter(Character $character){return DB::transaction(function()use($character){$now=CarbonImmutable::now();$lockedCharacter=Character::whereKey($character->id)->lockForUpdate()->firstOrFail();$inventory=CharacterItem::where('character_id',$lockedCharacter->id)->orderBy('id')->lockForUpdate()->get();$ownedInstances=ItemInstance::where('character_id',$lockedCharacter->id)->orderBy('id')->lockForUpdate()->get();$rewards=HuntReward::query()->select('hunt_rewards.*')->join('hunting_sessions','hunting_sessions.id','=','hunt_rewards.hunting_session_id')->where('hunting_sessions.character_id',$lockedCharacter->id)->where('hunt_rewards.status',HuntRewardStatus::PENDING)->orderBy('hunt_rewards.id')->lockForUpdate()->get();$rewardIds=$rewards->pluck('id')->sort()->values();$lines=$rewardIds->isEmpty()?collect():HuntRewardItem::whereIn('hunt_reward_id',$rewardIds)->orderBy('id')->lockForUpdate()->get();list($gold,$experience)=$this->aggregateValues($rewards);$itemIds=$inventory->pluck('item_id')->merge($ownedInstances->pluck('item_id'))->merge($lines->pluck('item_id'))->unique()->sort()->values();$items=$itemIds->isEmpty()?collect():Item::whereIn('id',$itemIds)->orderBy('id')->lockForUpdate()->get()->keyBy('id');if($items->count()!==$itemIds->count())throw new RuntimeException('Inventory or reward references a missing Item.');list($stackable,$uniqueLines,$lineCount,$total)=$this->planItems($lines,$items);$capacity=$this->capacity->fromLoadedState($lockedCharacter,$inventory,$lines,$items,$now,$ownedInstances);if(!$capacity->claimFits())throw new InsufficientInventoryCapacityForClaimException($capacity);if($rewards->isEmpty())return$this->emptyResult($lockedCharacter,$capacity);$operationUuid=DragonHeroUuid::versionFive('hunt-reward-claim:v1:'.$lockedCharacter->id.':'.$rewardIds->implode(','));if(!empty($stackable))$this->inventory->addManyLocked($lockedCharacter,$items,$stackable,$inventory);$claimedInstances=[];foreach($uniqueLines as $line)foreach($this->instances->createFromRewardLocked($lockedCharacter,$line,$items->get($line->item_id),$operationUuid,$now) as $entry)$claimedInstances[]=$entry->toArray();$walletEntry=null;if($gold>0)$walletEntry=$this->wallet->creditLocked($lockedCharacter,$gold,GoldReasonCode::HUNTING_REWARD,'Reclamación agregada de recompensas de cacería','hunt_reward_claim',(int)$rewardIds->first(),$operationUuid);$progression=$this->progression->grantExperienceLocked($lockedCharacter,$experience);foreach($rewards as $reward){if($reward->status!==HuntRewardStatus::PENDING)throw new RuntimeException('Invalid reward state transition.');$reward->status=HuntRewardStatus::CLAIMED;$reward->claimed_at=$now;$reward->save();}$updatedInventory=CharacterItem::where('character_id',$lockedCharacter->id)->orderBy('id')->get();$updatedInstances=ItemInstance::where('character_id',$lockedCharacter->id)->orderBy('id')->get();$updatedCapacity=$this->capacity->fromLoadedState($lockedCharacter,$updatedInventory,collect(),$items,$now,$updatedInstances);$claimedItems=[];foreach($stackable as $itemId=>$quantity){$item=$items->get($itemId);$claimedItems[]=['item_id'=>(int)$itemId,'item_code'=>$item->code,'item_name'=>$item->name,'quantity'=>$quantity];}return new HuntRewardClaimResult(['operation_uuid'=>$operationUuid,'claimed_rewards_count'=>$rewards->count(),'claimed_item_lines_count'=>$lineCount,'claimed_total_quantity'=>$total,'claimed_gold_amount'=>$gold,'claimed_experience_amount'=>$experience,'gold_transaction'=>$walletEntry?$walletEntry->toArray():null,'progression'=>$progression->toArray(),'claimed_items'=>$claimedItems,'claimed_item_instances'=>$claimedInstances,'inventory_capacity'=>$updatedCapacity->toArray(),'pending_rewards_summary'=>$this->rewards->summaryPendingForCharacter($lockedCharacter)]);},3);}private function emptyResult(Character $character,$capacity){return new HuntRewardClaimResult(['operation_uuid'=>null,'claimed_rewards_count'=>0,'claimed_item_lines_count'=>0,'claimed_total_quantity'=>0,'claimed_gold_amount'=>0,'claimed_experience_amount'=>0,'gold_transaction'=>null,'progression'=>['experience_before'=>(int)$character->experience,'experience_after'=>(int)$character->experience,'experience_gained'=>0,'level_before'=>(int)$character->level,'level_after'=>(int)$character->level,'levels_gained'=>0],'claimed_items'=>[],'claimed_item_instances'=>[],'inventory_capacity'=>$capacity->toArray(),'pending_rewards_summary'=>$this->rewards->summaryPendingForCharacter($character)]);}private function planItems($lines,$items){$stackable=[];$unique=[];$total=0;foreach($lines as $line){$quantity=$this->safePositive($line->quantity);$item=$items->get($line->item_id);if(!$item)throw new RuntimeException('Reward Item is missing.');$kind=$this->classification->classify($item);if($kind===ItemClassification::STACKABLE){$old=isset($stackable[$item->id])?$stackable[$item->id]:0;if($quantity>PHP_INT_MAX-$old)throw new InvalidArgumentException('Reward quantity overflow.');$stackable[$item->id]=$old+$quantity;}else$unique[]=$line;if($quantity>PHP_INT_MAX-$total)throw new InvalidArgumentException('Reward quantity overflow.');$total+=$quantity;}ksort($stackable,SORT_NUMERIC);return[$stackable,$unique,$lines->count(),$total];}private function aggregateValues($rewards){$gold=0;$experience=0;foreach($rewards as $reward){$g=$this->safeNonNegative($reward->gold_amount);$e=$this->safeNonNegative($reward->experience_amount);if($g>PHP_INT_MAX-$gold||$e>PHP_INT_MAX-$experience)throw new InvalidArgumentException('Reward value overflow.');$gold+=$g;$experience+=$e;}return[$gold,$experience];}private function safeNonNegative($value){if(is_int($value)&&$value>=0)return$value;if(is_string($value)&&preg_match('/^(0|[1-9][0-9]*)$/',$value)&&strlen($value)<=strlen((string)PHP_INT_MAX))return(int)$value;throw new InvalidArgumentException('Invalid reward value.');}private function safePositive($value){$value=$this->safeNonNegative($value);if($value<=0)throw new InvalidArgumentException('Invalid reward quantity.');return$value;}}
